const DEFAULT_CORS: Record<string, string> = {
  "access-control-allow-origin": "*",
  "access-control-allow-methods": "GET, POST, OPTIONS",
  "access-control-allow-headers":
    "authorization, x-client-info, apikey, content-type",
};

export function corsHeaders(
  extra?: Record<string, string>,
): Record<string, string> {
  return { ...DEFAULT_CORS, ...extra };
}

export function jsonResponse(
  body: unknown,
  status = 200,
  extra?: Record<string, string>,
): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { "content-type": "application/json", ...corsHeaders(extra) },
  });
}

export function handleOptions(): Response {
  return new Response(null, { status: 204, headers: corsHeaders() });
}

/**
 * Safe accessor for a top-level key on an unknown object.
 * Returns undefined if the object is null, not an object, or the key is missing.
 */
export function getField(obj: unknown, key: string): unknown {
  if (obj !== null && typeof obj === "object" && key in (obj as Record<string, unknown>)) {
    return (obj as Record<string, unknown>)[key];
  }
  return undefined;
}

function navigatePath(obj: unknown, path: string[]): unknown {
  let cur: unknown = obj;
  for (const k of path) {
    if (cur === null || cur === undefined || typeof cur !== "object") return undefined;
    if (!(k in (cur as Record<string, unknown>))) return undefined;
    cur = (cur as Record<string, unknown>)[k];
  }
  return cur;
}

/**
 * Traverses a nested path and returns a trimmed non-empty string,
 * converting finite numbers to strings. Returns null otherwise.
 */
export function getStr(obj: unknown, path: string[]): string | null {
  const v = navigatePath(obj, path);
  if (typeof v === "string" && v.trim()) return v;
  if (typeof v === "number" && Number.isFinite(v)) return String(v);
  return null;
}

/**
 * Traverses a nested path and returns a finite number,
 * parsing numeric strings. Returns null otherwise.
 */
export function getNum(obj: unknown, path: string[]): number | null {
  const v = navigatePath(obj, path);
  if (typeof v === "number" && Number.isFinite(v)) return v;
  if (typeof v === "string") {
    const n = Number(v);
    if (Number.isFinite(n)) return n;
  }
  return null;
}

/**
 * Traverses a nested path and returns the value if it is an array.
 * Returns null otherwise.
 */
export function getArr(obj: unknown, path: string[]): unknown[] | null {
  const v = navigatePath(obj, path);
  return Array.isArray(v) ? v : null;
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import type { Database } from "../../database.types.ts";

/** Typed Supabase client (Database from supabase gen types typescript). */
export type SupabaseClient = ReturnType<typeof createClient<Database>>;

/**
 * Creates a Supabase client with the service_role key (bypasses RLS).
 * Use for server-side admin operations only.
 * Client is typed with Database for type-safe queries and table inference.
 */
export function createAdminClient(): SupabaseClient {
  return createClient<Database>(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!,
  );
}

/**
 * Creates a Supabase client scoped to the requesting user's session.
 * Passes the Authorization header from the incoming request.
 * Client is typed with Database for type-safe queries.
 */
export function createUserClient(req: { headers: Headers }): SupabaseClient {
  const auth = req.headers.get("Authorization") ?? "";
  return createClient<Database>(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_ANON_KEY")!,
    { global: { headers: { Authorization: auth } } },
  );
}

// AES-GCM helpers for token encryption/decryption.
// Context: adapters/infra (shared crypto for ML/Shopee tokens).

export function strToUint8(str: string): Uint8Array {
  return new TextEncoder().encode(str);
}

export function uint8ToB64(bytes: Uint8Array): string {
  const bin = Array.from(bytes).map((b) => String.fromCharCode(b)).join("");
  return btoa(bin);
}

export function b64ToUint8(b64: string): Uint8Array {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

export async function importAesGcmKey(
  base64OrHexKey: string,
): Promise<CryptoKey> {
  const cleaned = base64OrHexKey.trim().replace(/^0x/i, "").replace(/[\s-]/g, "");
  let keyBytes: Uint8Array | null = null;

  try {
    const b64Bytes = b64ToUint8(cleaned);
    if ([16, 24, 32].includes(b64Bytes.length)) {
      keyBytes = b64Bytes;
    }
  } catch (_) {
    keyBytes = null;
  }

  if (!keyBytes) {
    const isHex = /^[0-9a-fA-F]+$/.test(cleaned) && cleaned.length % 2 === 0;
    if (!isHex) throw new Error("Invalid key format");
    const bytes = new Uint8Array(cleaned.length / 2);
    for (let i = 0; i < cleaned.length; i += 2) {
      bytes[i / 2] = parseInt(cleaned.slice(i, i + 2), 16);
    }
    if (![16, 24, 32].includes(bytes.length)) {
      throw new Error("Invalid key length");
    }
    keyBytes = bytes;
  }

  return crypto.subtle.importKey(
    "raw",
    keyBytes as BufferSource,
    { name: "AES-GCM" },
    false,
    ["encrypt", "decrypt"],
  );
}

export async function aesGcmEncryptToString(
  key: CryptoKey,
  plaintext: string,
): Promise<string> {
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const ct = await crypto.subtle.encrypt(
    { name: "AES-GCM", iv },
    key,
    strToUint8(plaintext) as BufferSource,
  );
  return `enc:gcm:${uint8ToB64(iv)}:${uint8ToB64(new Uint8Array(ct))}`;
}

export async function aesGcmDecryptFromString(
  key: CryptoKey,
  encStr: string,
): Promise<string> {
  const parts = encStr.split(":");
  if (parts.length !== 4 || parts[0] !== "enc" || parts[1] !== "gcm") {
    throw new Error("Invalid token format");
  }
  const iv = b64ToUint8(parts[2]) as BufferSource;
  const ct = b64ToUint8(parts[3]) as BufferSource;
  const pt = await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, ct);
  return new TextDecoder().decode(pt);
}

/**
 * Attempts to decrypt a token string. Returns plaintext if encrypted,
 * or the original string if it's not in enc:gcm format.
 */
export async function tryDecryptToken(
  key: CryptoKey,
  encStr: string,
): Promise<string> {
  const s = String(encStr || "");
  if (!s) return "";
  try {
    if (s.startsWith("enc:gcm:")) return await aesGcmDecryptFromString(key, s);
  } catch (_) {
    // Not encrypted or corrupted – return as-is
  }
  return s;
}

/**
 * Computes HMAC-SHA256 and returns uppercase hex string.
 * Used by Shopee API for request signing.
 */
export async function hmacSha256Hex(
  key: string,
  message: string,
): Promise<string> {
  const enc = new TextEncoder();
  const cryptoKey = await crypto.subtle.importKey(
    "raw",
    enc.encode(key),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
  const sig = await crypto.subtle.sign("HMAC", cryptoKey, enc.encode(message));
  const bytes = new Uint8Array(sig);
  let hex = "";
  for (let i = 0; i < bytes.length; i++) {
    hex += bytes[i].toString(16).padStart(2, "0");
  }
  return hex.toUpperCase();
}

// Entry point for the listing adapter layer.
// Call resolveAdapter(channel) to get the right adapter.

import { mercadoLivreAdapter } from './mercadoLivre.ts';
import { shopeeAdapter } from './shopee.ts';
import type { ListingAdapter } from './types.ts';

export type SupportedChannel = 'mercado-livre' | 'shopee';

const ADAPTERS: Record<SupportedChannel, ListingAdapter> = {
  'mercado-livre': mercadoLivreAdapter,
  'shopee': shopeeAdapter,
};

export function resolveAdapter(channel: string): ListingAdapter {
  const key = normalizeChannelKey(channel);
  const adapter = ADAPTERS[key];
  if (!adapter) {
    throw new Error(`No listing adapter found for channel: "${channel}"`);
  }
  return adapter;
}

function normalizeChannelKey(channel: string): SupportedChannel {
  const c = channel.toLowerCase().trim();
  if (c === 'mercado livre' || c === 'mercado-livre' || c === 'ml') return 'mercado-livre';
  if (c === 'shopee') return 'shopee';
  throw new Error(`Unknown channel: "${channel}"`);
}

export * from './types.ts';
export { mercadoLivreAdapter } from './mercadoLivre.ts';
export { shopeeAdapter } from './shopee.ts';
export { shouldWriteCanonical } from './shouldWriteCanonical.ts';
export { syncCanonicalFromPayload } from './syncCanonicalFromPayload.ts';
export {
  reconcileCanonicalFromStoredRaw,
  fetchMlSupplementary,
  fetchShopeeSupplementary,
  fetchChannelSupplementary,
  isMercadoLivreChannel,
  isShopeeChannel,
} from './reconcileCanonical.ts';
export { resolveCanonicalFees } from './shared/feesResolve.ts';

// Mercado Livre → canonical listing adapter.
// Transforms a raw Mercado Livre item payload into NormalizedListing.

import type {
  AdapterContext,
  CanonicalAttribute,
  CanonicalFees,
  CanonicalListing,
  CanonicalMetrics,
  CanonicalPicture,
  CanonicalQuality,
  CanonicalShipping,
  CanonicalVariation,
  ListingAdapter,
  NormalizedListing,
} from './types.ts';
import { mapMercadoLivreStatus } from './shared/statusMapping.ts';
import {
  mapMercadoLivreLogistic,
  mapMercadoLivreShippingTags,
} from './shared/logisticMapping.ts';
import { mapMercadoLivreQuality } from './shared/qualityMapping.ts';
import { parseMercadoLivreDimensions, parseMercadoLivrePackage } from './shared/dimensionsParse.ts';
import { resolveCanonicalFees } from './shared/feesResolve.ts';

// ---------------------------------------------------------------------------
// Helper types for the raw Mercado Livre payload
// ---------------------------------------------------------------------------

interface MlItem {
  id?: string;
  title?: string;
  price?: number;
  base_price?: number;
  currency_id?: string;
  status?: string;
  sub_status?: string[];
  available_quantity?: number;
  sold_quantity?: number;
  listing_type_id?: string;
  catalog_listing?: boolean;
  catalog_product_id?: string;
  category_id?: string;
  permalink?: string;
  pictures?: Array<{ id?: string; url?: string; secure_url?: string }>;
  video_id?: string;
  variations?: MlVariation[];
  attributes?: MlAttribute[];
  shipping?: MlShipping;
  seller_custom_field?: string;
  date_created?: string;
  last_updated?: string;
  tags?: string[];
  condition?: string;
  sale_terms?: Array<{ id: string; value_name?: string }>;
}

interface MlVariation {
  id?: number | string;
  seller_custom_field?: string;
  price?: number;
  original_price?: number;
  available_quantity?: number;
  sold_quantity?: number;
  picture_ids?: string[];
  attribute_combinations?: Array<{
    id?: string;
    name?: string;
    value_id?: string;
    value_name?: string;
  }>;
}

interface MlAttribute {
  id?: string;
  name?: string;
  value_id?: string;
  value_name?: string;
  value_struct?: unknown;
  attribute_group_id?: string;
  tags?: Record<string, unknown>;
}

interface MlShipping {
  logistic_type?: string;
  shipping_mode?: string;
  free_shipping?: boolean;
  free_methods?: unknown[];
  tags?: string[];
  dimensions?: string;
  local_pick_up?: boolean;
}

// ---------------------------------------------------------------------------
// Adapter implementation
// ---------------------------------------------------------------------------

function normalizeMLItem(payload: unknown, ctx: AdapterContext): NormalizedListing {
  const extra = ctx.extra;
  const raw = payload as Record<string, unknown>;

  // The item may be directly in raw or nested under raw.data
  const item: MlItem =
    (raw['data'] as MlItem) ?? (raw as unknown as MlItem);

  const itemId: string = String(item.id ?? raw['marketplace_item_id'] ?? '');

  // -------------------------------------------------------------------------
  // Listing core
  // -------------------------------------------------------------------------
  const sku =
    item.seller_custom_field ??
    item.attributes?.find((a) => a.id === 'SELLER_SKU')?.value_name ??
    null;

  const thumbnail =
    item.pictures?.[0]?.secure_url ??
    item.pictures?.[0]?.url ??
    null;

  const listing: CanonicalListing = {
    marketplace_name: 'Mercado Livre',
    marketplace_item_id: itemId,
    title: item.title ?? '',
    sku,
    category_id: item.category_id ?? null,
    category_path: null,
    permalink: item.permalink ?? null,
    thumbnail_url: thumbnail,
    has_variations: Array.isArray(item.variations) && item.variations.length > 0,
    condition: normalizeCondition(item.condition),

    status: mapMercadoLivreStatus(item.status),
    status_raw: item.status ?? '',
    sub_status: Array.isArray(item.sub_status) ? item.sub_status : [],
    pause_reason: item.sale_terms?.find((t) => t.id === 'PAUSE_REASON')?.value_name ?? null,

    price: item.price ?? null,
    original_price: item.base_price ?? null,
    promo_price: null,
    currency: item.currency_id ?? 'BRL',

    available_quantity: item.available_quantity ?? 0,
    sold_quantity: item.sold_quantity ?? 0,

    listing_type_id: item.listing_type_id ?? null,
    catalog_listing: item.catalog_listing ?? null,
    catalog_product_id: item.catalog_product_id ?? null,

    marketplace_created_at: raw['date_created'] as string ?? item.date_created ?? null,
    marketplace_updated_at: raw['last_updated'] as string ?? item.last_updated ?? null,
  };

  // -------------------------------------------------------------------------
  // Variations
  // -------------------------------------------------------------------------
  const variations: CanonicalVariation[] = (item.variations ?? []).map((v, i) => ({
    variation_id: String(v.id ?? i),
    sku: v.seller_custom_field ?? null,
    price: v.price ?? null,
    original_price: v.original_price ?? null,
    promo_price: null,
    available_quantity: v.available_quantity ?? 0,
    sold_quantity: v.sold_quantity ?? 0,
    image_url: null, // Mercado Livre pictures are at item level; map by picture_ids below
    attributes: (v.attribute_combinations ?? []).map((ac) => ({
      id: ac.id ?? '',
      name: ac.name ?? '',
      value_id: ac.value_id,
      value_name: ac.value_name,
    })),
    primary_for_listing: i === 0,
  }));

  // -------------------------------------------------------------------------
  // Pictures
  // -------------------------------------------------------------------------
  const pictures: CanonicalPicture[] = (item.pictures ?? []).map((p, idx) => ({
    external_picture_id: p.id ?? null,
    url: p.url ?? '',
    secure_url: p.secure_url ?? null,
    position: idx,
    is_video: false,
    video_url: null,
    variation_id: null,
  }));

  // Video (Mercado Livre stores video_id, not a direct URL)
  if (item.video_id) {
    pictures.push({
      external_picture_id: item.video_id,
      url: `https://www.youtube.com/watch?v=${item.video_id}`,
      secure_url: null,
      position: pictures.length,
      is_video: true,
      video_url: `https://www.youtube.com/watch?v=${item.video_id}`,
      variation_id: null,
    });
  }

  // -------------------------------------------------------------------------
  // Attributes
  // -------------------------------------------------------------------------
  const attributes: CanonicalAttribute[] = (item.attributes ?? []).map((a) => ({
    attribute_id: a.id ?? '',
    attribute_name: a.name ?? null,
    value_id: a.value_id ?? null,
    value_name: a.value_name ?? null,
    value_struct: a.value_struct != null ? (a.value_struct as Record<string, unknown>) : null,
    is_required: a.tags?.['required'] === true,
    is_variation_attr: a.tags?.['variation_attribute'] === true,
  }));

  // -------------------------------------------------------------------------
  // Shipping
  // -------------------------------------------------------------------------
  const ship = item.shipping;
  const dims = extra?.packageDims
    ? parseMercadoLivrePackage(extra.packageDims)
    : parseMercadoLivreDimensions(ship?.dimensions);

  const shippingTags = Array.isArray(ship?.tags) ? ship!.tags : [];
  const detectedTypes = mapMercadoLivreShippingTags(shippingTags);
  const primaryLogistic = mapMercadoLivreLogistic(ship?.logistic_type);

  const shipping: CanonicalShipping = {
    logistic_type: primaryLogistic,
    logistic_types: detectedTypes.length > 0 ? detectedTypes : [primaryLogistic],
    shipping_mode: ship?.shipping_mode ?? null,
    free_shipping: ship?.free_shipping ?? false,
    mandatory_free_shipping:
      Array.isArray(ship?.tags) && ship!.tags!.includes('mandatory_free_shipping'),
    local_pick_up: ship?.local_pick_up ?? false,
    package_length_cm: dims.length_cm,
    package_width_cm: dims.width_cm,
    package_height_cm: dims.height_cm,
    package_weight_g: dims.weight_g,
  };

  // -------------------------------------------------------------------------
  // Metrics (from marketplace_metrics row when available)
  // -------------------------------------------------------------------------
  const m = extra?.metricsRow ?? {};
  const metrics: CanonicalMetrics = {
    visits_total: num(m['visits_total']) ?? 0,
    visits_last_30_days: num(m['visits_last_30_days']) ?? 0,
    impressions: num(m['impressions']) ?? null,
    sales_total: item.sold_quantity ?? 0,
    sales_last_30_days: null,
    conversion_rate: num(m['conversion_rate']) ?? 0,
    likes_total: 0,
    comments_total: 0,
    rating_average: num(m['rating_average']) ?? null,
    reviews_count: num(m['reviews_count']) ?? 0,
  };

  // -------------------------------------------------------------------------
  // Quality
  // -------------------------------------------------------------------------
  const q = extra?.qualityRow ?? {};
  const { level, score } = mapMercadoLivreQuality(
    String(q['quality_level'] ?? ''),
    num(q['listing_quality']),
  );
  const quality: CanonicalQuality = {
    quality_score: score,
    quality_level: level,
    missing_attributes: [],
    unfinished_tasks: [],
  };

  // -------------------------------------------------------------------------
  // Fees (universal resolver → marketplace_listing_fees)
  // -------------------------------------------------------------------------
  const lp = (extra?.listingPricesRow?.['listing_prices'] ?? null) as Record<string, unknown> | null;
  const fees: CanonicalFees = resolveCanonicalFees({
    marketplaceName: 'Mercado Livre',
    salePrice: listing.price,
    payloadVersion: ctx.payloadVersion ?? null,
    mlListingPrices: lp,
  });

  return { listing, variations, pictures, attributes, shipping, metrics, quality, fees };
}

function normalizeCondition(raw?: string): 'new' | 'used' | 'refurbished' | null {
  if (!raw) return null;
  if (raw === 'new') return 'new';
  if (raw === 'used') return 'used';
  if (raw === 'refurbished') return 'refurbished';
  return null;
}

function num(v: unknown): number | null {
  const n = Number(v);
  return v != null && v !== '' && isFinite(n) ? n : null;
}

export const mercadoLivreAdapter: ListingAdapter = {
  channel: 'mercado-livre',
  normalize: normalizeMLItem,
};

// Rebuilds canonical listing tables from stored raw payload + optional ML supplementary rows.

import { resolveAdapter } from './index.ts';
import { upsertCanonicalListing } from './upsertCanonical.ts';
import { shouldWriteCanonical } from './shouldWriteCanonical.ts';
import type { AdapterNormalizeExtra, ProviderFeeRuleSnapshot } from './types.ts';

interface SupabaseClient {
  // deno-lint-ignore no-explicit-any
  from: (table: string) => any;
}

export function isMercadoLivreChannel(marketplaceName: string): boolean {
  const c = String(marketplaceName || '').toLowerCase();
  return c.includes('mercado') || c === 'ml';
}

export function isShopeeChannel(marketplaceName: string): boolean {
  return String(marketplaceName || '').toLowerCase().includes('shopee');
}

function extractCategoryId(payload: unknown): string | null {
  const raw = payload as Record<string, unknown>;
  const data = (raw?.['data'] ?? raw) as Record<string, unknown>;
  const base = (data?.['base_info'] ?? {}) as Record<string, unknown>;
  const cat = base?.['category_id'] ?? data?.['category_id'] ?? raw?.['category_id'];
  return cat != null ? String(cat) : null;
}

async function fetchFeeRuleByCategory(
  supabase: SupabaseClient,
  marketplaceName: string,
  categoryId: string | null,
): Promise<ProviderFeeRuleSnapshot | null> {
  const ids = categoryId ? [categoryId, '_default'] : ['_default'];
  for (const cid of ids) {
    const { data } = await supabase
      .from('marketplace_provider_fee_rules')
      .select('commission_percentage, commission_fixed_fee, listing_fee_amount, currency, source')
      .eq('marketplace_name', marketplaceName)
      .eq('category_id', cid)
      .maybeSingle();
    if (data) {
      return data as ProviderFeeRuleSnapshot;
    }
  }
  return null;
}

async function learnShopeeFeeFromOrders(
  supabase: SupabaseClient,
  organizationId: string,
  marketplaceItemId: string,
  categoryId: string | null,
): Promise<Pick<AdapterNormalizeExtra, 'observedAvgCommissionAmount' | 'observedAvgCommissionPercentage'>> {
  const { data: orders } = await supabase
    .from('marketplace_orders_presented_new')
    .select('items_total_sale_fee, items_total_amount')
    .eq('organizations_id', organizationId)
    .eq('first_item_id', marketplaceItemId)
    .eq('marketplace_name', 'Shopee')
    .gt('items_total_sale_fee', 0)
    .order('created_at', { ascending: false })
    .limit(25);

  const rows = (orders ?? []) as Array<{ items_total_sale_fee?: number; items_total_amount?: number }>;
  if (!rows.length) return {};

  const avgFee =
    rows.reduce((s, r) => s + Number(r.items_total_sale_fee ?? 0), 0) / rows.length;

  const withAmount = rows.filter((r) => Number(r.items_total_amount) > 0);
  let avgPct: number | null = null;
  if (withAmount.length) {
    avgPct =
      withAmount.reduce(
        (s, r) => s + (Number(r.items_total_sale_fee ?? 0) / Number(r.items_total_amount)) * 100,
        0,
      ) / withAmount.length;
  }

  if (categoryId && avgPct != null && avgPct > 0) {
    await supabase.from('marketplace_provider_fee_rules').upsert(
      {
        marketplace_name: 'Shopee',
        category_id: categoryId,
        site_id: 'BR',
        commission_percentage: Math.round(avgPct * 100) / 100,
        commission_fixed_fee: 0,
        listing_fee_amount: 0,
        source: 'order_items_avg',
        metadata: { sample_size: rows.length, marketplace_item_id: marketplaceItemId },
      },
      { onConflict: 'marketplace_name,category_id,site_id' },
    );
  }

  return {
    observedAvgCommissionAmount: avgFee > 0 ? avgFee : null,
    observedAvgCommissionPercentage: avgPct,
  };
}

export async function fetchShopeeSupplementary(
  supabase: SupabaseClient,
  organizationId: string,
  marketplaceItemId: string,
  payload: unknown,
): Promise<AdapterNormalizeExtra> {
  const categoryId = extractCategoryId(payload);
  const feeRule = await fetchFeeRuleByCategory(supabase, 'Shopee', categoryId);
  const observed = await learnShopeeFeeFromOrders(
    supabase,
    organizationId,
    marketplaceItemId,
    categoryId,
  );
  return { feeRule, ...observed };
}

/** Channel-specific enrichment (metrics, prices, fee rules). */
export async function fetchChannelSupplementary(
  supabase: SupabaseClient,
  organizationId: string,
  marketplaceName: string,
  marketplaceItemId: string,
  payload?: unknown,
): Promise<AdapterNormalizeExtra | undefined> {
  if (isMercadoLivreChannel(marketplaceName)) {
    return fetchMlSupplementary(supabase, organizationId, marketplaceItemId);
  }
  if (isShopeeChannel(marketplaceName)) {
    return fetchShopeeSupplementary(supabase, organizationId, marketplaceItemId, payload);
  }
  return undefined;
}

export async function fetchMlSupplementary(
  supabase: SupabaseClient,
  organizationId: string,
  marketplaceItemId: string,
): Promise<AdapterNormalizeExtra> {
  const [metricsRes, pricesRes] = await Promise.all([
    supabase
      .from('marketplace_metrics')
      .select('*')
      .eq('organizations_id', organizationId)
      .eq('marketplace_name', 'Mercado Livre')
      .eq('marketplace_item_id', marketplaceItemId)
      .maybeSingle(),
    supabase
      .from('marketplace_item_prices')
      .select('*')
      .eq('organizations_id', organizationId)
      .eq('marketplace_name', 'Mercado Livre')
      .eq('marketplace_item_id', marketplaceItemId)
      .maybeSingle(),
  ]);

  const metricsRow = (metricsRes.data ?? null) as Record<string, unknown> | null;
  return {
    metricsRow,
    listingPricesRow: (pricesRes.data ?? null) as Record<string, unknown> | null,
    qualityRow: metricsRow,
  };
}

export async function loadListingRawPayload(
  supabase: SupabaseClient,
  organizationId: string,
  marketplaceItemId: string,
): Promise<{
  marketplaceName: string;
  integrationId: string | null;
  payload: unknown;
} | null> {
  const { data: rawItem } = await supabase
    .from('marketplace_items_raw')
    .select('*')
    .eq('organizations_id', organizationId)
    .eq('marketplace_item_id', marketplaceItemId)
    .order('updated_at', { ascending: false })
    .limit(1)
    .maybeSingle();

  if (rawItem) {
    return {
      marketplaceName: String(rawItem.marketplace_name ?? rawItem.marketplace ?? ''),
      integrationId: rawItem.integration_id ?? null,
      payload: rawItem,
    };
  }

  const { data: legacyItem } = await supabase
    .from('marketplace_items')
    .select('*')
    .eq('organizations_id', organizationId)
    .eq('marketplace_item_id', marketplaceItemId)
    .maybeSingle();

  if (!legacyItem) return null;

  return {
    marketplaceName: String(legacyItem.marketplace_name ?? 'Mercado Livre'),
    integrationId: legacyItem.integration_id ?? null,
    payload: legacyItem.data ? { data: legacyItem.data, ...legacyItem } : legacyItem,
  };
}

export interface ReconcileCanonicalParams {
  organizationId: string;
  marketplaceName: string;
  marketplaceItemId: string;
  integrationId?: string | null;
  payloadSource?: string;
  payloadOverride?: unknown;
  /** Backfill / sync-one: write canonical even if listings_canonical flag is off. */
  force?: boolean;
}

/** Non-throwing: logs warnings on failure. */
export async function reconcileCanonicalFromStoredRaw(
  supabase: SupabaseClient,
  params: ReconcileCanonicalParams,
): Promise<{ ok: boolean; listingId?: string; error?: string; skipped?: boolean }> {
  const {
    organizationId,
    marketplaceName,
    marketplaceItemId,
    integrationId: integrationIdParam,
    payloadSource = 'reconcile',
    payloadOverride,
    force,
  } = params;

  try {
    const enabled = await shouldWriteCanonical(supabase, organizationId, marketplaceName, { force });
    if (!enabled) {
      return { ok: true, skipped: true };
    }

    let payload = payloadOverride;
    let integrationId = integrationIdParam ?? null;
    let mktName = marketplaceName;

    if (payload == null) {
      const loaded = await loadListingRawPayload(supabase, organizationId, marketplaceItemId);
      if (!loaded?.marketplaceName) {
        return { ok: false, error: 'Item not found in marketplace_items_raw or marketplace_items' };
      }
      payload = loaded.payload;
      mktName = loaded.marketplaceName;
      integrationId = integrationId ?? loaded.integrationId;
    }

    const extra = await fetchChannelSupplementary(
      supabase,
      organizationId,
      mktName,
      marketplaceItemId,
      payload,
    );

    const adapter = resolveAdapter(mktName);
    const wrapped =
      payload && typeof payload === 'object' && !('data' in (payload as Record<string, unknown>))
        ? {
            data: payload,
            marketplace_item_id: marketplaceItemId,
            marketplace_name: mktName,
          }
        : payload;

    const normalized = adapter.normalize(wrapped, {
      organizationId,
      integrationId,
      payloadVersion: 1,
      extra,
    });

    await supabase.from('marketplace_listings_raw').upsert(
      {
        organizations_id: organizationId,
        marketplace_name: mktName,
        marketplace_item_id: marketplaceItemId,
        integration_id: integrationId,
        payload: (wrapped as Record<string, unknown>)?.data ?? wrapped,
        payload_version: 1,
        payload_source: payloadSource,
        fetched_at: new Date().toISOString(),
      },
      {
        onConflict: 'organizations_id,marketplace_name,marketplace_item_id,payload_version',
        ignoreDuplicates: true,
      },
    );

    const { listingId, error } = await upsertCanonicalListing(supabase, normalized, {
      organizationsId: organizationId,
      integrationId,
    });

    if (error) {
      return { ok: false, error: error.message };
    }
    return { ok: true, listingId };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return { ok: false, error: msg };
  }
}

// Parses dimension and weight data from both Mercado Livre and Shopee payloads.

export interface ParsedDimensions {
  length_cm: number | null;
  width_cm: number | null;
  height_cm: number | null;
  weight_g: number | null;
}

// Mercado Livre stores dimensions as a string: "HxWxL,weight"
// e.g. "12x8x20,800"  or "12.5x8.0x20.0,850.0"
export function parseMercadoLivreDimensions(raw: string | null | undefined): ParsedDimensions {
  if (!raw) return { length_cm: null, width_cm: null, height_cm: null, weight_g: null };

  const cleaned = raw.replace(/\s/g, '');
  const [dimPart, weightPart] = cleaned.split(',');
  const dims = (dimPart ?? '').split('x').map(Number);

  return {
    height_cm: isFinite(dims[0]) ? dims[0] : null,
    width_cm: isFinite(dims[1]) ? dims[1] : null,
    length_cm: isFinite(dims[2]) ? dims[2] : null,
    weight_g: weightPart != null && isFinite(Number(weightPart)) ? Number(weightPart) : null,
  };
}

// Mercado Livre also stores explicit package_*_cm columns (from sync jobs)
export function parseMercadoLivrePackage(item: Record<string, unknown>): ParsedDimensions {
  // Try explicit columns first (already numeric)
  const h = num(item['package_height_cm'] ?? item['package_height']);
  const w = num(item['package_width_cm'] ?? item['package_width']);
  const l = num(item['package_length_cm'] ?? item['package_length']);
  const weight = num(item['package_weight_g'] ?? item['package_weight']);

  if (h !== null || w !== null || l !== null || weight !== null) {
    return { height_cm: h, width_cm: w, length_cm: l, weight_g: weight };
  }

  // Fall back to the dimensions string in data.shipping.dimensions
  const data = item['data'] as Record<string, unknown> | undefined;
  const shipping = data?.['shipping'] as Record<string, unknown> | undefined;
  const dimString = shipping?.['dimensions'] as string | undefined;
  return parseMercadoLivreDimensions(dimString);
}

// Shopee stores dimensions in base_info.dimension (object) and base_info.weight (grams)
export function parseShopeeDimensions(
  dimension: { package_length?: number; package_width?: number; package_height?: number } | null | undefined,
  weightGrams: number | null | undefined,
): ParsedDimensions {
  return {
    length_cm: dimension?.package_length ?? null,
    width_cm: dimension?.package_width ?? null,
    height_cm: dimension?.package_height ?? null,
    weight_g: weightGrams ?? null,
  };
}

function num(value: unknown): number | null {
  const n = Number(value);
  return value != null && value !== '' && isFinite(n) ? n : null;
}

// Channel-agnostic fee resolver → CanonicalFees (marketplace_listing_fees).
// Mercado Livre and Shopee inputs are normalized here so the DB stores one shape.

import type { CanonicalFees } from '../types.ts';
import type { ProviderFeeRuleSnapshot } from '../types.ts';

export interface FeesResolveInput {
  marketplaceName: string;
  salePrice: number | null;
  payloadVersion?: number | null;
  currency?: string;
  /** Mercado Livre: marketplace_item_prices.listing_prices jsonb */
  mlListingPrices?: Record<string, unknown> | null;
  /** Shopee: base_info slice */
  shopeePayload?: {
    commission_fee?: number | null;
    commission_rate?: number | null;
    logistic_info?: Array<{ shipping_fee_subsidy?: number; enabled?: boolean }>;
  } | null;
  /** Cached category rule (marketplace_provider_fee_rules) */
  feeRule?: ProviderFeeRuleSnapshot | null;
  /** Learned from realized orders (marketplace_orders_presented_new) */
  observedAvgCommissionAmount?: number | null;
  observedAvgCommissionPercentage?: number | null;
}

function num(v: unknown): number | null {
  const n = Number(v);
  return v != null && v !== '' && Number.isFinite(n) ? n : null;
}

function computeTotal(fees: CanonicalFees): void {
  if (
    fees.commission_amount != null ||
    fees.listing_fee_amount != null ||
    fees.shipping_subsidy != null
  ) {
    fees.total_fees_estimated =
      (fees.commission_amount ?? 0) +
      (fees.listing_fee_amount ?? 0) +
      (fees.shipping_subsidy ?? 0);
  }
}

function resolveMercadoLivreFees(input: FeesResolveInput): CanonicalFees {
  const lp = (input.mlListingPrices ?? {}) as Record<string, unknown>;
  const saleFeeDetails = (lp['sale_fee_details'] ?? {}) as Record<string, unknown>;
  const prices0 = Array.isArray(lp['prices']) ? (lp['prices'] as unknown[])[0] : null;
  const shippingCost = prices0 && typeof prices0 === 'object'
    ? (prices0 as Record<string, unknown>)['shipping_cost'] as Record<string, unknown> | undefined
    : undefined;

  const fees: CanonicalFees = {
    currency: input.currency ?? 'BRL',
    commission_amount: num(lp['sale_fee_amount']) ?? num(
      (prices0 as Record<string, unknown> | undefined)?.['sale_fee'] &&
        typeof (prices0 as Record<string, unknown>)['sale_fee'] === 'object'
        ? ((prices0 as Record<string, unknown>)['sale_fee'] as Record<string, unknown>)['amount']
        : null,
    ),
    commission_percentage: num(saleFeeDetails['percentage_fee']),
    commission_fixed_fee: num(saleFeeDetails['fixed_fee']),
    listing_fee_amount: num(lp['listing_fee_amount']),
    shipping_subsidy: num(shippingCost?.['amount']),
    total_fees_estimated: null,
    source_payload_version: input.payloadVersion ?? null,
  };

  computeTotal(fees);
  return fees;
}

function maxShippingSubsidyShopee(
  logistics: Array<{ shipping_fee_subsidy?: number; enabled?: boolean }> | undefined,
): number | null {
  if (!Array.isArray(logistics) || !logistics.length) return null;
  let max = 0;
  let found = false;
  for (const l of logistics) {
    if (l?.enabled === false) continue;
    const sub = num(l?.shipping_fee_subsidy);
    if (sub != null && sub > max) {
      max = sub;
      found = true;
    }
  }
  return found ? max : null;
}

function resolveShopeeFees(input: FeesResolveInput): CanonicalFees {
  const base = input.shopeePayload ?? {};
  const price = input.salePrice;
  const rule = input.feeRule;
  const pctFromRule = num(rule?.commission_percentage);
  const pctFromPayload = num(base.commission_rate);
  const pctFromOrders = num(input.observedAvgCommissionPercentage);
  const commissionPct = pctFromPayload ?? pctFromRule ?? pctFromOrders ?? null;

  let commissionAmount = num(base.commission_fee);
  if (commissionAmount == null && num(input.observedAvgCommissionAmount) != null) {
    commissionAmount = num(input.observedAvgCommissionAmount);
  }
  if (commissionAmount == null && commissionPct != null && price != null && price > 0) {
    commissionAmount = Math.round((price * commissionPct / 100) * 100) / 100;
  }

  const fees: CanonicalFees = {
    currency: input.currency ?? 'BRL',
    commission_amount: commissionAmount,
    commission_percentage: commissionPct,
    commission_fixed_fee: num(rule?.commission_fixed_fee) ?? 0,
    listing_fee_amount: num(rule?.listing_fee_amount) ?? 0,
    shipping_subsidy: maxShippingSubsidyShopee(base.logistic_info),
    total_fees_estimated: null,
    source_payload_version: input.payloadVersion ?? null,
  };

  computeTotal(fees);
  return fees;
}

/** Resolves canonical fees for any supported marketplace. */
export function resolveCanonicalFees(input: FeesResolveInput): CanonicalFees {
  const mkt = String(input.marketplaceName || '').toLowerCase();
  if (mkt.includes('mercado') || mkt === 'ml') {
    return resolveMercadoLivreFees(input);
  }
  if (mkt.includes('shopee')) {
    return resolveShopeeFees(input);
  }

  return {
    currency: input.currency ?? 'BRL',
    commission_amount: null,
    commission_percentage: null,
    commission_fixed_fee: null,
    listing_fee_amount: null,
    shipping_subsidy: null,
    total_fees_estimated: null,
    source_payload_version: input.payloadVersion ?? null,
  };
}

import type { LogisticTypeCanonical } from '../types.ts';

// ---------------------------------------------------------------------------
// Mercado Livre
// ---------------------------------------------------------------------------

const ML_LOGISTIC_MAP: Record<string, LogisticTypeCanonical> = {
  fulfillment: 'full',
  fbm: 'full',
  self_service: 'flex',
  xd_drop_off: 'envios',
  cross_docking: 'envios',
  drop_off: 'correios',
  me1: 'custom',
  custom: 'custom',
  not_specified: 'custom',
};

export function mapMercadoLivreLogistic(rawType: string | null | undefined): LogisticTypeCanonical {
  if (!rawType) return 'unknown';
  return ML_LOGISTIC_MAP[rawType.toLowerCase()] ?? 'custom';
}

// Mercado Livre items may expose multiple shipping tags; each tag maps to a type
export function mapMercadoLivreShippingTags(
  tags: string[] | null | undefined,
): LogisticTypeCanonical[] {
  if (!Array.isArray(tags) || tags.length === 0) return [];
  const seen = new Set<LogisticTypeCanonical>();
  for (const tag of tags) {
    const t = tag.toLowerCase();
    if (t.includes('fulfillment') || t.includes('fbm')) seen.add('full');
    else if (t.includes('self_service') || t.includes('flex')) seen.add('flex');
    else if (t.includes('drop_off')) seen.add('correios');
    else if (t.includes('cross_docking') || t.includes('xd_drop')) seen.add('envios');
    else if (t.includes('me1')) seen.add('custom');
  }
  return [...seen];
}

// ---------------------------------------------------------------------------
// Shopee
// The priority order for "primary" logistic: full > shopee_xpress > flex > correios > retire
// ---------------------------------------------------------------------------

const LOGISTIC_PRIORITY: LogisticTypeCanonical[] = [
  'full',
  'shopee_xpress',
  'flex',
  'correios',
  'retire',
  'custom',
  'unknown',
];

function shopeeLogisticFromName(name: string): LogisticTypeCanonical {
  const n = name.toLowerCase();
  if (n.includes('fulfillment') || n.includes('fbs')) return 'full';
  if (n.includes('xpress')) return 'shopee_xpress';
  if (n.includes('same day') || n.includes('sameday')) return 'flex';
  if (n.includes('retire') || n.includes('retirada') || n.includes('pickup')) return 'retire';
  // "Padrão", "Standard", or generic drop-off maps to correios
  return 'correios';
}

export function mapShopeeLogistics(
  logisticInfo: Array<{ logistic_name?: string; enabled?: boolean; is_fulfillment_by_shopee?: boolean }> | null | undefined,
): { logisticType: LogisticTypeCanonical; logisticTypes: LogisticTypeCanonical[] } {
  if (!Array.isArray(logisticInfo) || logisticInfo.length === 0) {
    return { logisticType: 'unknown', logisticTypes: [] };
  }

  const enabled = logisticInfo.filter((l) => l.enabled !== false);
  const seen = new Set<LogisticTypeCanonical>();

  for (const l of enabled) {
    if (l.is_fulfillment_by_shopee) {
      seen.add('full');
      continue;
    }
    if (l.logistic_name) {
      seen.add(shopeeLogisticFromName(l.logistic_name));
    }
  }

  const types = [...seen];
  // Determine primary type by priority order
  const primary =
    LOGISTIC_PRIORITY.find((p) => types.includes(p)) ?? (types[0] ?? 'unknown');

  return { logisticType: primary, logisticTypes: types };
}

import type { QualityLevelCanonical } from '../types.ts';

// ---------------------------------------------------------------------------
// Mercado Livre
// quality_level comes as 'bronze'|'silver'|'gold'|'platinum' or as a numeric
// score (0-100) from listing_quality.
// ---------------------------------------------------------------------------

const ML_QUALITY_LEVEL_MAP: Record<string, QualityLevelCanonical> = {
  platinum: 'excellent',
  gold: 'good',
  silver: 'medium',
  bronze: 'low',
  incomplete: 'incomplete',
};

export function mapMercadoLivreQuality(
  qualityLevel: string | null | undefined,
  score: number | null | undefined,
): { level: QualityLevelCanonical; score: number | null } {
  const level =
    ML_QUALITY_LEVEL_MAP[String(qualityLevel ?? '').toLowerCase()] ?? scoreToLevel(score);
  return { level, score: score ?? null };
}

function scoreToLevel(score: number | null | undefined): QualityLevelCanonical {
  if (score == null) return 'unknown';
  if (score >= 80) return 'excellent';
  if (score >= 60) return 'good';
  if (score >= 40) return 'medium';
  if (score > 0) return 'low';
  return 'incomplete';
}

// ---------------------------------------------------------------------------
// Shopee
// quality_level in content_diagnosis_result is typically a string: 'GOOD',
// 'MEDIUM', 'LOW', 'POOR', 'INCOMPLETE'.
// ---------------------------------------------------------------------------

const SHOPEE_QUALITY_MAP: Record<string, QualityLevelCanonical> = {
  EXCELLENT: 'excellent',
  GOOD: 'good',
  MEDIUM: 'medium',
  LOW: 'low',
  POOR: 'low',
  INCOMPLETE: 'incomplete',
};

export function mapShopeeQuality(
  qualityLevel: string | null | undefined,
): QualityLevelCanonical {
  if (!qualityLevel) return 'unknown';
  return SHOPEE_QUALITY_MAP[qualityLevel.toUpperCase()] ?? 'unknown';
}

import type { ListingStatusCanonical } from '../types.ts';

const ML_STATUS_MAP: Record<string, ListingStatusCanonical> = {
  active: 'active',
  paused: 'paused',
  closed: 'closed',
  under_review: 'under_review',
  inactive: 'closed',
};

const SHOPEE_STATUS_MAP: Record<string, ListingStatusCanonical> = {
  NORMAL: 'active',
  UNLIST: 'paused',
  BANNED: 'deleted',
  DELETED: 'deleted',
  REVIEWING: 'under_review',
};

export function mapMercadoLivreStatus(raw: string | null | undefined): ListingStatusCanonical {
  if (!raw) return 'active';
  return ML_STATUS_MAP[raw.toLowerCase()] ?? 'active';
}

export function mapShopeeStatus(raw: string | null | undefined): ListingStatusCanonical {
  if (!raw) return 'active';
  return SHOPEE_STATUS_MAP[raw.toUpperCase()] ?? 'active';
}

// Shopee → canonical listing adapter.
// Transforms a raw Shopee item payload (as stored in marketplace_items_raw.data)
// into NormalizedListing.

import type {
  AdapterContext,
  CanonicalAttribute,
  CanonicalFees,
  CanonicalListing,
  CanonicalMetrics,
  CanonicalPicture,
  CanonicalQuality,
  CanonicalShipping,
  CanonicalVariation,
  ListingAdapter,
  NormalizedListing,
} from './types.ts';
import { mapShopeeStatus } from './shared/statusMapping.ts';
import { mapShopeeLogistics } from './shared/logisticMapping.ts';
import { mapShopeeQuality } from './shared/qualityMapping.ts';
import { parseShopeeDimensions } from './shared/dimensionsParse.ts';
import { resolveCanonicalFees } from './shared/feesResolve.ts';

// ---------------------------------------------------------------------------
// Raw Shopee payload shapes
// ---------------------------------------------------------------------------

interface ShopeeBaseInfo {
  item_id?: number | string;
  item_name?: string;
  item_status?: string;
  item_sku?: string;
  category_id?: number | string;
  price_info?: Array<{ current_price?: number; original_price?: number; inflated_price?: number }>;
  image?: { image_url_list?: string[]; image_id_list?: string[] };
  video_info?: Array<{ video_url?: string; thumbnail_url?: string; duration?: number }>;
  attribute_list?: Array<{
    attribute_id?: number | string;
    attribute_name?: string;
    attribute_value_list?: Array<{ value_id?: number | string; original_value?: string }>;
    is_mandatory?: boolean;
    input_validation_type?: string;
  }>;
  logistic_info?: Array<{
    logistic_id?: number | string;
    logistic_name?: string;
    enabled?: boolean;
    is_free?: boolean;
    is_fulfillment_by_shopee?: boolean;
    shipping_fee?: number;
    shipping_fee_subsidy?: number;
  }>;
  dimension?: {
    package_length?: number;
    package_width?: number;
    package_height?: number;
  };
  weight?: number;    // in grams
  has_model?: boolean;
  condition?: string;
  stock_info_v2?: { seller_stock?: Array<{ stock?: number }>; summary_info?: { total_available_stock?: number } };
  commission_fee?: number;
  commission_rate?: number;
}

interface ShopeeExtraInfo {
  views?: number;
  likes?: number;
  sale?: number;
  comment_count?: number;
  rating_star?: number;
}

interface ShopeeContentDiagnosis {
  quality_level?: string;
  unfinished_task?: unknown[];
  missing_mandatory?: string[];
}

interface ShopeeModel {
  model_id?: number | string;
  model_sku?: string;
  price_info?: Array<{ current_price?: number; original_price?: number }>;
  stock_info_v2?: {
    seller_stock?: Array<{ stock?: number }>;
    summary_info?: { total_available_stock?: number };
  };
  tier_variation_index?: number[];
  image?: { image_url?: string };
}

interface ShopeePayload {
  base_info?: ShopeeBaseInfo;
  extra_info?: ShopeeExtraInfo;
  content_diagnosis_result?: ShopeeContentDiagnosis;
  item_promotion?: unknown;
  model_list?: ShopeeModel[];
}

// ---------------------------------------------------------------------------
// Adapter implementation
// ---------------------------------------------------------------------------

function normalizeShopeeItem(payload: unknown, ctx: AdapterContext): NormalizedListing {
  const raw = payload as Record<string, unknown>;

  // The payload may be nested under raw.data (from marketplace_items_raw)
  const shopee: ShopeePayload =
    (raw['data'] as ShopeePayload) ?? (raw as unknown as ShopeePayload);

  const base = shopee.base_info ?? {};
  const extra = shopee.extra_info ?? {};
  const diagnosis = shopee.content_diagnosis_result ?? {};
  const models = shopee.model_list ?? [];

  const itemId = String(base.item_id ?? raw['marketplace_item_id'] ?? '');

  // -------------------------------------------------------------------------
  // Price — use base price_info, fall back to first model
  // -------------------------------------------------------------------------
  const priceInfo = Array.isArray(base.price_info) ? base.price_info[0] : null;
  const price = priceInfo?.current_price ?? models[0]?.price_info?.[0]?.current_price ?? null;
  const originalPrice =
    priceInfo?.original_price ?? models[0]?.price_info?.[0]?.original_price ?? null;

  // -------------------------------------------------------------------------
  // Stock
  // -------------------------------------------------------------------------
  const totalStock =
    base.stock_info_v2?.summary_info?.total_available_stock ??
    (base.stock_info_v2?.seller_stock ?? []).reduce((acc, s) => acc + (s.stock ?? 0), 0) ??
    0;

  // -------------------------------------------------------------------------
  // Listing core
  // -------------------------------------------------------------------------
  const thumbnail = base.image?.image_url_list?.[0] ?? null;

  const listing: CanonicalListing = {
    marketplace_name: 'Shopee',
    marketplace_item_id: itemId,
    title: base.item_name ?? '',
    sku: base.item_sku ?? null,
    category_id: base.category_id != null ? String(base.category_id) : null,
    category_path: null,
    permalink: null,
    thumbnail_url: thumbnail,
    has_variations: base.has_model === true && models.length > 0,
    condition: normalizeShopeeCondition(base.condition),

    status: mapShopeeStatus(base.item_status),
    status_raw: base.item_status ?? '',
    sub_status: [],
    pause_reason: null,

    price: price ?? null,
    original_price: originalPrice ?? null,
    promo_price: null,
    currency: 'BRL',

    available_quantity: totalStock,
    sold_quantity: extra.sale ?? 0,

    listing_type_id: null,
    catalog_listing: null,
    catalog_product_id: null,

    marketplace_created_at: null,
    marketplace_updated_at: raw['updated_at'] as string ?? null,
  };

  // -------------------------------------------------------------------------
  // Variations
  // -------------------------------------------------------------------------
  const variations: CanonicalVariation[] = models.map((m, i) => {
    const varStock =
      m.stock_info_v2?.summary_info?.total_available_stock ??
      (m.stock_info_v2?.seller_stock ?? []).reduce((acc, s) => acc + (s.stock ?? 0), 0) ??
      0;

    return {
      variation_id: String(m.model_id ?? i),
      sku: m.model_sku ?? null,
      price: m.price_info?.[0]?.current_price ?? null,
      original_price: m.price_info?.[0]?.original_price ?? null,
      promo_price: null,
      available_quantity: varStock,
      sold_quantity: 0,
      image_url: m.image?.image_url ?? null,
      attributes: [],  // tier variation names resolved at display layer
      primary_for_listing: i === 0,
    };
  });

  // -------------------------------------------------------------------------
  // Pictures
  // -------------------------------------------------------------------------
  const pictures: CanonicalPicture[] = (base.image?.image_url_list ?? []).map((url, idx) => ({
    external_picture_id: base.image?.image_id_list?.[idx] ?? null,
    url,
    secure_url: null,
    position: idx,
    is_video: false,
    video_url: null,
    variation_id: null,
  }));

  // Videos
  for (const v of base.video_info ?? []) {
    if (v.video_url) {
      pictures.push({
        external_picture_id: null,
        url: v.thumbnail_url ?? v.video_url,
        secure_url: null,
        position: pictures.length,
        is_video: true,
        video_url: v.video_url,
        variation_id: null,
      });
    }
  }

  // -------------------------------------------------------------------------
  // Attributes
  // -------------------------------------------------------------------------
  const attributes: CanonicalAttribute[] = (base.attribute_list ?? []).map((a) => {
    const firstVal = a.attribute_value_list?.[0];
    return {
      attribute_id: String(a.attribute_id ?? ''),
      attribute_name: a.attribute_name ?? null,
      value_id: firstVal?.value_id != null ? String(firstVal.value_id) : null,
      value_name: firstVal?.original_value ?? null,
      value_struct: null,
      is_required: a.is_mandatory ?? null,
      is_variation_attr: false,
    };
  });

  // -------------------------------------------------------------------------
  // Shipping
  // -------------------------------------------------------------------------
  const dims = parseShopeeDimensions(base.dimension, base.weight);
  const { logisticType, logisticTypes } = mapShopeeLogistics(
    base.logistic_info as Parameters<typeof mapShopeeLogistics>[0],
  );

  const hasFreeShipping = (base.logistic_info ?? []).some((l) => l.is_free);

  const shipping: CanonicalShipping = {
    logistic_type: logisticType,
    logistic_types: logisticTypes,
    shipping_mode: 'shopee_logistics',
    free_shipping: hasFreeShipping,
    mandatory_free_shipping: false,
    local_pick_up: (base.logistic_info ?? []).some((l) =>
      (l.logistic_name ?? '').toLowerCase().includes('retire') ||
      (l.logistic_name ?? '').toLowerCase().includes('retirada'),
    ),
    package_length_cm: dims.length_cm,
    package_width_cm: dims.width_cm,
    package_height_cm: dims.height_cm,
    package_weight_g: dims.weight_g,
  };

  // -------------------------------------------------------------------------
  // Metrics
  // -------------------------------------------------------------------------
  const views = extra.views ?? 0;
  const sales = extra.sale ?? 0;
  const conversionRate = views > 0 ? sales / views : 0;

  const metrics: CanonicalMetrics = {
    visits_total: views,
    visits_last_30_days: views,   // Shopee exposes only a running total
    impressions: null,
    sales_total: sales,
    sales_last_30_days: null,
    conversion_rate: conversionRate,
    likes_total: extra.likes ?? 0,
    comments_total: extra.comment_count ?? 0,
    rating_average: extra.rating_star ?? null,
    reviews_count: extra.comment_count ?? 0,
  };

  // -------------------------------------------------------------------------
  // Quality
  // -------------------------------------------------------------------------
  const quality: CanonicalQuality = {
    quality_score: null,
    quality_level: mapShopeeQuality(diagnosis.quality_level),
    missing_attributes: diagnosis.missing_mandatory ?? [],
    unfinished_tasks: diagnosis.unfinished_task ?? [],
  };

  // -------------------------------------------------------------------------
  // Fees (universal resolver: payload + category rules + order history)
  // -------------------------------------------------------------------------
  const fees: CanonicalFees = resolveCanonicalFees({
    marketplaceName: 'Shopee',
    salePrice: price ?? null,
    payloadVersion: ctx.payloadVersion ?? null,
    shopeePayload: {
      commission_fee: base.commission_fee ?? null,
      commission_rate: base.commission_rate ?? null,
      logistic_info: base.logistic_info,
    },
    feeRule: ctx.extra?.feeRule ?? null,
    observedAvgCommissionAmount: ctx.extra?.observedAvgCommissionAmount ?? null,
    observedAvgCommissionPercentage: ctx.extra?.observedAvgCommissionPercentage ?? null,
  });

  return { listing, variations, pictures, attributes, shipping, metrics, quality, fees };
}

function normalizeShopeeCondition(raw?: string): 'new' | 'used' | 'refurbished' | null {
  if (!raw) return null;
  const r = raw.toLowerCase();
  if (r === 'new' || r === 'NEW') return 'new';
  if (r === 'used' || r === 'USED') return 'used';
  return null;
}

